 2→import type {
 3→  PlatformAPI,
 4→  PlatformClipboard,
 5→  PlatformShell,
 6→  PlatformWindow,
 7→} from './types';
 8→
 9→const SETTINGS_STORAGE_KEY = 'settings-general';
10→
11→function isSettingsWithPosition(v: unknown): v is { windowPosition: string } {
12→  return (
13→    typeof v === 'object' &&
14→    v !== null &&
15→    'windowPosition' in v &&
16→    typeof v.windowPosition === 'string'
17→  );
18→}
19→
20→const clipboard: PlatformClipboard = {
21→  async writeText(text: string) {
22→    await navigator.clipboard.writeText(text);
23→  },
24→  async readText() {
25→    return navigator.clipboard.readText();
26→  },
27→};
28→
29→const shell: PlatformShell = {
30→  async openUrl(url: string) {
31→    try {
32→      const parsed = new URL(url);
33→      if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
34→        return;
35→      }
36→    } catch {
37→      return;
38→    }
39→    window.open(url, '_blank', 'noopener,noreferrer');
40→  },
41→  async openDeepLink(url: string) {
42→    const anchor = document.createElement('a');
43→    anchor.href = url;
44→    anchor.click();
45→  },
46→};
47→
48→const platformWindow: PlatformWindow = {
49→  async hide() {
50→    const { getCurrentWindow } = await import('@tauri-apps/api/window');
51→    await getCurrentWindow().hide();
52→  },
53→  async setPositionPreference(position: string) {
54→    const { invoke } = await import('@tauri-apps/api/core');
55→    await invoke('set_window_position_pref', { position });
56→  },
57→  async onFocusChanged(handler: (focused: boolean) => void) {
58→    const { getCurrentWindow } = await import('@tauri-apps/api/window');
59→    return getCurrentWindow().onFocusChanged(({ payload: focused }) => {
60→      handler(focused);
61→    });
62→  },
63→  async onTrayNavigate(handler: (target: string) => void) {
64→    const { listen } = await import('@tauri-apps/api/event');
65→    return listen<string>('tray-navigate', event => {
66→      handler(event.payload);
67→    });
68→  },
69→  async syncStoredPositionToBackend() {
70→    const stored = storageGet(SETTINGS_STORAGE_KEY, isSettingsWithPosition);
71→    if (!stored?.windowPosition) return;
72→
73→    const { invoke } = await import('@tauri-apps/api/core');
74→    await invoke('set_window_position_pref', {
75→      position: stored.windowPosition,
76→    });
77→  },
78→};
79→
80→export const tauriPlatform: PlatformAPI = {
81→  clipboard,
82→  shell,
83→  window: platformWindow,
84→};
