 1→import { useCallback, useEffect, useRef } from 'react';
 2→import { getPlatform, isTauri } from '../platform';
 3→
 4→export { isTauri };
 5→
 6→interface UseWindowOptions {
 7→  onShow?: () => void;
 8→  onHide?: () => void;
 9→  onTrayNavigate?: (target: string) => void;
10→}
11→
12→export function useWindow(options: UseWindowOptions = {}) {
13→  const onShowRef = useRef(options.onShow);
14→  const onHideRef = useRef(options.onHide);
15→  const onTrayNavigateRef = useRef(options.onTrayNavigate);
16→
17→  useEffect(() => {
18→    onShowRef.current = options.onShow;
19→    onHideRef.current = options.onHide;
20→    onTrayNavigateRef.current = options.onTrayNavigate;
21→  });
22→
23→  useEffect(() => {
24→    if (!isTauri) return;
25→
26→    let unlistenFocus: (() => void) | undefined;
27→    let unlistenTray: (() => void) | undefined;
28→    let cancelled = false;
29→
30→    const platformWindow = getPlatform().window;
31→
32→    (async () => {
33→      await platformWindow.syncStoredPositionToBackend();
34→
35→      const focusUnsub = await platformWindow.onFocusChanged(focused => {
36→        if (focused) {
37→          onShowRef.current?.();
38→        } else {
39→          onHideRef.current?.();
40→        }
41→      });
42→
43→      const trayUnsub = await platformWindow.onTrayNavigate(target => {
44→        onTrayNavigateRef.current?.(target);
45→      });
46→
47→      if (cancelled) {
48→        focusUnsub();
49→        trayUnsub();
50→      } else {
51→        unlistenFocus = focusUnsub;
52→        unlistenTray = trayUnsub;
53→      }
54→    })();
55→
56→    return () => {
57→      cancelled = true;
58→      unlistenFocus?.();
59→      unlistenTray?.();
60→    };
61→  }, []);
62→
63→  const hideWindow = useCallback(async () => {
64→    if (!isTauri) return;
65→    await getPlatform().window.hide();
66→  }, []);
67→
68→  const setPositionPreference = useCallback(async (position: string) => {
69→    if (!isTauri) return;
70→    await getPlatform().window.setPositionPreference(position);
71→  }, []);
72→
73→  return {
74→    hideWindow,
75→    setPositionPreference,
76→    isTauri,
77→  };
78→}
