197→interface ContentBlock {
198→  type: 'text' | 'tool_use' | 'tool_result';
199→  text?: string;
200→  name?: string;
201→  input?: unknown;
202→  content?:
203→    | string
204→    | Array<{
205→        type: string;
206→        text?: string;
207→      }>;
208→}
