210→interface StreamMessage {
211→  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
212→  subtype?: string;
213→  role?: 'assistant' | 'user';
214→  event?: {
215→    type: string;
216→    delta?: {
217→      type: string;
218→      text?: string;
219→    };
220→  };
221→  result?: string;
222→  message?: {
223→    role?: string;
